"use strict";(self.webpackChunkmy_website=self.webpackChunkmy_website||[]).push([[487],{8725:e=>{e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"/observability-metrics-and-monitoring","metadata":{"permalink":"/pt-br/blog/observability-metrics-and-monitoring","editUrl":"https://github.com/vinicinbgs/vinicinbgs.github.io/blob/main/blog/obervability-metrics-and-monitoring/index.mdx","source":"@site/i18n/pt-br/docusaurus-plugin-content-blog/obervability-metrics-and-monitoring/index.mdx","title":"Desvendando os Segredos do Sistema: A Magia da Observabilidade","description":"How can we listening the software statistics?","date":"2024-06-04T00:00:00.000Z","tags":[{"inline":false,"label":"observabilidade","permalink":"/pt-br/blog/tags/observability","description":"Acompanhe o desempenho e a disponibilidade de seus servi\xe7os e aplicativos."}],"readingTime":15.415,"hasTruncateMarker":false,"authors":[],"frontMatter":{"title":"Desvendando os Segredos do Sistema: A Magia da Observabilidade","date":"2024-06-04T00:00:00.000Z","slug":"/observability-metrics-and-monitoring","description":"How can we listening the software statistics?","tags":["observabilidade"]},"unlisted":false,"nextItem":{"title":"Understand Shell Script","permalink":"/pt-br/blog/understand-shell-script"}},"content":"import Tabs from \'@theme/Tabs\';\\nimport TabItem from \'@theme/TabItem\';\\n\\n\\nO Objetivo do artigo \xe9 instruir sobre os conceitos de Observabilidade, Logs, M\xe9tricas e Tracing baseando-se na literatura e experi\xeancia pr\xe1tica em grandes empresas.  \\n\\nVamos aprender a aplica-los em um projeto pr\xe1tico e como eles se relacionam.\\n\\n\\n# Table of Contents\\n\\n- [Table of Contents](#table-of-contents)\\n  - [\ud83d\udd2d Afinal, Observabilidade](#-afinal-observabilidade)\\n    - [Tr\xeas Pilares da Observabilidade](#tr\xeas-pilares-da-observabilidade)\\n    - [Conclus\xe3o](#conclus\xe3o)\\n  - [ 1. \ud83d\udcdc Logs: Segredos Escondidos no C\xf3digo](#-1--logs-segredos-escondidos-no-c\xf3digo)\\n    - [ 1.1. Introdu\xe7\xe3o](#-11-introdu\xe7\xe3o)\\n    - [ 1.2. N\xedveis de Logs](#-12-n\xedveis-de-logs)\\n    - [ 1.3. Formato de Logs](#-13-formato-de-logs)\\n      - [1.3.1. Estruturados](#131-estruturados)\\n      - [1.3.2. Semi-Estruturados](#132-semi-estruturados)\\n      - [1.3.3. Desestruturados](#133-desestruturados)\\n    - [ 1.4. Implementa\xe7\xe3o](#-14-implementa\xe7\xe3o)\\n    - [ 1.5. Arquitetura](#-15-arquitetura)\\n    - [Conclus\xe3o](#conclus\xe3o-1)\\n  - [ 2. \ud83d\udcc8 M\xe9tricas: Decifrando o Desempenho do Software](#-2--m\xe9tricas-decifrando-o-desempenho-do-software)\\n    - [2.1. M\xe9tricas de Recursos (CPU, Mem\xf3ria, Disco, Rede)](#21-m\xe9tricas-de-recursos-cpu-mem\xf3ria-disco-rede)\\n    - [2.2. M\xe9tricas de Servi\xe7o (Four Golden Signals)](#22-m\xe9tricas-de-servi\xe7o-four-golden-signals)\\n    - [2.2. Algumas Boas Pr\xe1ticas](#22-algumas-boas-pr\xe1ticas)\\n    - [2.3. Arquitetura](#23-arquitetura)\\n    - [Conclus\xe3o](#conclus\xe3o-2)\\n  - [ 3. \ud83d\udc63 Tracing: Rastreando Segredos](#-3--tracing-rastreando-segredos)\\n      - [Exemplo](#exemplo)\\n    - [3.1. Distributed Tracing](#31-distributed-tracing)\\n    - [Conclus\xe3o](#conclus\xe3o-3)\\n  - [ 4. \ud83d\udea8 Monitoramento: Desvendando Mist\xe9rios em Tempo Real](#-4--monitoramento-desvendando-mist\xe9rios-em-tempo-real)\\n    - [Conclus\xe3o](#conclus\xe3o-4)\\n  - [Refer\xeancias](#refer\xeancias)\\n\\n> \u201cYou can\'t manage what you can\'t measure.\u201d\\n> \\n> -- <cite>Peter Drucker</cite>\\n\\n---\\n\\n## <a name=\\"what-is-observability\\"></a>\ud83d\udd2d Afinal, Observabilidade\\n\\nO termo surgiu em 1960 na \xe1rea de engenharia de controle, introduzido pelo engenheiro Rudolf E. K\xe1lm\xe1n, e foi popularizado por [On The General Theory of Control Systems](https://www.control.utoronto.ca/~broucke/ece410f/kalman.pdf).\\n\\nNa Teoria de Controle, Observabilidade \xe9 uma medida dos estados internos de um sistema que podem ser inferidos a partir do conhecimento de suas sa\xeddas externas.\\n\\nO que significa que a `observabilidade prop\u014de saber como o sistema chegou em um estado olhando suas sa\xeddas`.\\n\\nDessa forma permite lidar com problemas atuais e at\xe9 solucionar problemas novos.\\n\\nMas nem tudo \xe9 m\xe1gica... Para ser capaz de identificar um estado de um sistema olhando suas sa\xeddas, a aplica\xe7\xe3o deve ser devidamente `instrumentada`, ou seja, deve emitir sinais que possam ser capturados e analisados. \\n\\nDividimos esses sinais em 3 pilares `traces`, `m\xe9tricas` e `logs`. Por\xe9m s\xf3 ter os sinais n\xe3o \xe9 suficiente, \xe9 necess\xe1rio coletar, transmitir e armazenar esses dados.\\n\\nA coleta, transmiss\xe3o e armazenamento desses dados chamamos de `Telemetria`.\\n\\n![telemetria](./telemetry.png)\\n*Generated by DALL-E*\\n\\nUma aplica\xe7\xe3o \xe9 devidamente instrumentada quando os desenvolvedores n\xe3o precisam adicionar mais instrumentos para solucionar um problema, porque eles t\xeam todas as informa\xe7\xf5es de que precisam, ou seja, sem a necessidade de fazer um novo deploy para adicionar mais instrumentos. `Entenda como instrumentos: softwares novos, altera\xe7\xf5es de arquivos ou configura\xe7\xf5es, etc.`\\n\\nClaro, essa maturidade \xe9 atingida com o tempo, e \xe9 um processo cont\xednuo de melhoria, seria imposs\xedvel instrumentar tudo de uma vez, pois sempre haver\xe1 problemas que n\xe3o se manifestaram... ainda.\\n\\n### Tr\xeas Pilares da Observabilidade\\n| Pilar    | Descri\xe7\xe3o                                                                                       |\\n| -------- | ----------------------------------------------------------------------------------------------- |\\n| M\xe9tricas | Mede quantitivamente, comumente usada para comparar, rastrear desempenho em uma linha do tempo. |\\n| Logs     | Registro de que um evento ocorreu                                                               |\\n| Tracing  | Tracing \xe9 um mecanismo para acompanhar o fluxo e a progress\xe3o dos dados de um software          |\\n\\n### Conclus\xe3o\\n\\nAplica\xe7\xf5es bem instrumentadas s\xe3o capazes de responder perguntas sobre seu comportamento an\xe1lisando-as de fora, e isso \xe9 o que chamamos de `Observabilidade`.\\n\\nInstrumentar aplica\xe7\xf5es \xe9 o ato de emitir sinais, esses sinais s\xe3o divididos em 3 pilares: `traces`, `m\xe9tricas` e `logs`.\\n\\n`Telemetria` \xe9 o processo de coletar, transmitir e armazenar esses sinais.\\n\\n---\\n\\n## <a name=\\"what-are-logs\\"></a> 1. \ud83d\udcdc Logs: Segredos Escondidos no C\xf3digo\\n\\n### <a name=\\"log-introduction\\"></a> 1.1. Introdu\xe7\xe3o\\n\\nTodo software executa m\xe9todos/fun\xe7\xf5es, essas execu\xe7\xf5es na maioria das vezes tem algo as nos dizer que fazem valer a pena serem registradas. Ent\xe3o...  \\n`Logs s\xe3o registro de eventos que ocorrem no software.`  \\n\\nAbaixo listo alguns tipos de logs:\\n- <u>Application Logs</u>\\n- Audit Logs\\n- Authorization and Access Logs\\n- Change Logs\\n- Event Logs\\n- Resource Logs\\n- Server Logs\\n- System Logs\\n- Threat Logs\\n- Transaction Logs\\n\\nVamos abordar apenas os logs de aplica\xe7\xe3o, que s\xe3o logs gerados por uma aplica\xe7\xe3o em execu\xe7\xe3o.\\n\\n**Normalmente em um registro de log de aplica\xe7\xe3o encontramos:**\\n- `Timestamp`\\n- `Mensagem`\\n- `N\xedvel`\\n- `Dados de Contexto`\\n\\n### <a name=\\"log-level\\"></a> 1.2. N\xedveis de Logs\\n- `DEBUG` - Informa\xe7\xf5es detalhadas, normalmente de interesse apenas ao desenvolvedor.\\n- `INFO` - Captura que eventos ocorreram, mas n\xe3o s\xe3o erros.\\n- `WARN` - Indica que algo inesperado aconteceu, mas o software ainda \xe9 capaz de funcionar.\\n- `ERROR` - Indica que pelo menos um componente do sistema falhou e pode interferir em parte ou no funcionamento geral.\\n- `FATAL` - Indica que o sistema n\xe3o pode continuar a funcionar.\\n\\n\\n### <a name=\\"log-formats\\"></a> 1.3. Formato de Logs\\n\\nAbaixo vamos ver algumas estruturas de logs mais encontradas no mercado. O JSON costuma ser o mais utilizado por ser f\xe1cil de parsear e por ser estruturado.\\n\\n#### 1.3.1. Estruturados\\n\\n<Tabs>\\n  <TabItem value=\\"json\\" label=\\"JSON\\" default>\\n    ![structured_logs](./structured_logs.png)\\n\\n    No exemplo acima perceba que existem dois campos `trace_id` e `span_id`, vamos aborda-los mais a frente.\\n  </TabItem>\\n  <TabItem value=\\"xml\\" label=\\"XML\\">\\n    ```xml\\n    <log>\\n      <timestamp>2024-07-10T14:45:23Z</timestamp>\\n      <level>INFO</level>\\n      <message>User logged in</message>\\n      <user>john.doe</user>\\n      <ip>127.0.0.1</ip>\\n    </log>\\n    ```\\n  </TabItem>\\n  <TabItem value=\\"csv\\" label=\\"CSV\\">\\n    ```csv\\n    timestamp,level,message,user,ip\\n    2024-07-10T14:45:23Z,INFO,User logged in,john.doe,127.0.0.1\\n    ```\\n  </TabItem>\\n  <TabItem value=\\"logfmt\\" label=\\"Logfmt\\">\\n    ```txt\\n    timestamp=\\"2024-07-10T14:45:23Z\\" level=INFO message=\\"User logged in\\" user=\\"john.doe\\" ip=\\"127.0.0.1\\"\\n    ```\\n  </TabItem>\\n  <TabItem value=\\"syslog\\" label=\\"Syslog (RFC 5424)\\">\\n    ```txt\\n    <165>1 2003-10-11T22:14:15.003Z mymachine.example.com evntslog - ID47 [exampleSDID@32473 iut=\\"3\\" eventSource=\\"Application\\" eventID=\\"1011\\"][examplePriority@32473 class=\\"high\\"]\\n    ```\\n  </TabItem>\\n</Tabs>\\n\\n---\\n\\n#### 1.3.2. Semi-Estruturados\\n<Tabs>\\n  <TabItem value=\\"cef\\" label=\\"Common Event Format (CEF)\\">\\n    ```txt\\n    CEF:0|Security|ThreatDetection|1.0|100|User logged in|5|msg=User logged in src=127.0.0.1 user=john.doe\\n    ```\\n  </TabItem>\\n  <TabItem value=\\"clf\\" label=\\"NCSA Common Log Format (CLF)\\">\\n    ```txt\\n    192.168.0.1 - jane [08/Jul/2024:10:23:45 +0000] \\"POST /login HTTP/1.1\\" 302 512\\n    ```\\n  </TabItem>\\n</Tabs>\\n\\n---\\n\\n#### 1.3.3. Desestruturados\\n\\n![unstructured_logs](./unstructured_logs.png)\\n\\n---\\n\\nQual a diferen\xe7a entre `Semi-Estruturado`, `Estruturado` e `Desestruturado`?  \\n\\n**Semi-Estruturados** possuem uma estrutura fixa, por\xe9m os campos n\xe3o s\xe3o fixos.  \\n> *Por exemplo, `Logfmt` tem sempre a mesma estrutura `key=value` com separador de espa\xe7o, por\xe9m os campos podem variar.*\\n\\n**Estruturados** possuem uma estrutura fixa e os campos s\xe3o fixos.  \\n> *Por exemplo, `JSON` possui sempre os mesmos campos (se assim for implementado), ou seja, todos os logs possuem os mesmos campos, como `timestamp`, `level`, `message` e `extra`, por\xe9m os valores podem variar.*\\n\\n**Desestruturados** n\xe3o possuem uma estrutura fixa, ou seja, os campos e valores podem variar. \\n> *Por exemplo, logs de texto puro.*\\n\\n### <a name=\\"log-implementation\\"></a> 1.4. Implementa\xe7\xe3o\\n\\nComo utilizar logs em uma aplica\xe7\xe3o? Abaixo vemos um snippet de c\xf3digo da aplica\xe7\xe3o Flask em Python que construi para exemplificar esse artigo.\\n\\n```py\\n@app.route(\'/\')\\ndef hello():\\n  message = f\\"Hello from {MS_NAME}!\\"\\n  Logger().info(\'app.py\', {\\"response\\": message, \\"status\\": \\"200\\", \\"method\\": \\"GET\\", \\"path\\": \\"/\\", \\"app\\": MS_NAME})\\n  \\n  return message\\n```\\n\\nO c\xf3digo est\xe1 emitindo um log estruturado atrav\xe9s da abstra\xe7\xe3o `Logger` para sobrescrever o comportamento padr\xe3o do `logging` do Python.\\n\\nAgora vamos an\xe1lisar o output em JSON do log gerado por esse c\xf3digo.\\n\\n```json\\n{\\n  \\"timestamp\\": \\"2024-07-05 19:59:37\\",\\n  \\"level\\": \\"INFO\\",\\n  \\"message\\": \\"app.py\\",\\n  \\"extra\\": {\\n    \\"response\\": \\"Hello from ms-one!\\",\\n    \\"status\\": \\"200\\",\\n    \\"method\\": \\"GET\\",\\n    \\"path\\": \\"/\\",\\n    \\"app\\": \\"ms-one\\"\\n  }\\n}\\n```\\n\\nO destino desse output pode ser um arquivo, um banco de dados, um servi\xe7o de log, etc. No nosso caso estamos apenas imprimindo o log no console `stdout` e `stderr`.\\n\\n### <a name=\\"log-architecture\\"></a> 1.5. Arquitetura\\n\\n![Logs](./logging.png)\\n\\n:::info\\n\\nNo exemplo acima o `promtail` \xe9 um `agente que coleta logs dos containers` e envia para o `Loki`, que \xe9 um `sistema de armazenamento de logs` enquanto o `Grafana` \xe9 uma `ferramenta de visualiza\xe7\xe3o de logs` que consome diretamente do Loki.\\n\\n:::\\n\\n**Armazenar logs acaba se tornando caro \ud83d\udcb0 ao longo do tempo**, por isso \xe9 importante definir os eventos que realmente possuem valor e padronizar a estrutura de output.  \\n\\nBusque **pontos estrat\xe9gicos dentro do c\xf3digo da aplica\xe7\xe3o para emitir logs com contextos relevantes**, isso vai ajudar a trackear o comportamento do software do lado de fora usando alguma ferramenta de visualiza\xe7\xe3o de logs e  permitir que com esses dados sejam montadas dashboards com m\xe9tricas que ir\xe3o facilitar a descoberta de problemas e auxiliar\xe3o em tomadas de decis\xf5es.\\n\\n### Conclus\xe3o\\n\\nO log estruturado permite que voc\xea fa\xe7a consultas mais complexas de forma mais f\xe1cil, e consiga atrav\xe9s dos logs construir m\xe9tricas.  \\n\\nNo log desestruturado o parseamento \xe9 mais dif\xedcil pois a estrutura n\xe3o \xe9 fixa, e a constru\xe7\xe3o de m\xe9tricas pode se tornar mais complexa. Pode ocasionar na quebra de dashboards e m\xe9tricas dependendo de como a consulta foi constru\xedda.\\n\\n:::warning\\nN\xe3o que n\xe3o seja poss\xedvel fazer m\xe9tricas com os logs Semi-Estruturado e Desestruturado, mas acaba se tornando dif\xedcil quando n\xe3o se possui um padr\xe3o.\\n:::\\n\\n:::tip\\n**Defina as boas pr\xe1ticas de logging para sua aplica\xe7\xe3o e siga-as:**\\n- Defina os n\xedveis de logs que devem ser emitidos em produ\xe7\xe3o, n\xe3o emita `debug`.\\n- Defina o formato de output (JSON, XML, CSV...).\\n  - Defina os campos que devem ser emitidos.\\n  - Defina quando usar log de erro.\\n  - Defina quando usar log de info.\\n  - Defina quando usar log de warning.\\n  - Defina quando usar log de fatal.\\n- Projete o c\xf3digo para emitir logs em pontos estrat\xe9gicos.\\n- Defina o destino dos logs (stdout, stderr, arquivo, banco de dados, servi\xe7o de log, etc)\\n- Defina a politica de reten\xe7\xe3o de logs (X dias).\\n:::\\n\\n---\\n\\n## <a name=\\"what-are-metrics\\"></a> 2. \ud83d\udcc8 M\xe9tricas: Decifrando o Desempenho do Software\\n\\nM\xe9tricas s\xe3o valores capturados em seus sistemas em um ponto espec\xedfico no tempo.  \\n\\n**Exemplos:**\\n- o n\xfamero de usu\xe1rios que logaram em seus sistema nas \xfaltimas 2h\\n- o n\xfamero de requisi\xe7\xf5es que sua aplica\xe7\xe3o recebeu nas \xfaltimas 24h\\n- o tempo m\xe9dio de resposta de uma requisi\xe7\xe3o dentro das \xfaltimas 1h\\n\\nPodem ser coletadas uma vez por segundo, uma por minuto ou em outro intervalo regular para monitorar um sistema ao longo do tempo. Seus dados s\xe3o comumente armazenados em um banco de dados de s\xe9ries temporais, como o InfluxDB, Prometheus, Graphite, etc. No Prometheus a coleta \xe9 feita atrav\xe9s de `scraping`.\\n\\nTamb\xe9m construimos m\xe9tricas atrav\xe9s dos logs de aplica\xe7\xe3o, filtrando e agregando os dados dentro de um intervalo de tempo. Chamamos essa t\xe9cnica de [White-box monitoring](https://sre.google/sre-book/monitoring-distributed-systems/).\\n\\nPor Exemplo, a partir dos logs da aplica\xe7\xe3o que possuem o campo `extra_path=\\"/health\\"`, podemos contar quantas vezes a rota `/health` foi requisitada em um intervalo de tempo. Veja abaixo:\\n\\n![Metrics](./metrics_graph.png)\\n\\nForam feitos 3 requests para a rota `/health` em um intervalo de `~1 minutos`. Neste caso construimos uma m\xe9trica de `Tr\xe1fego` (Traffic).\\n\\n### 2.1. M\xe9tricas de Recursos (CPU, Mem\xf3ria, Disco, Rede)\\n\\nM\xe9tricas de recursos s\xe3o m\xe9tricas que medem o uso de recursos de um sistema, como CPU, mem\xf3ria, disco e rede. Essas m\xe9tricas s\xe3o essenciais para monitorar a sa\xfade e o desempenho de um sistema e identificar gargalos e problemas de desempenho.\\n\\n| Sinal       | Descri\xe7\xe3o                                                                             |\\n| ----------- | ------------------------------------------------------------------------------------- |\\n| Utilization | Mede a quantidade de recurso que est\xe1 sendo usada.                                    |\\n| Saturation  | Mede o grau em que um recurso est\xe1 perto de sua capacidade m\xe1xima ou al\xe9m.            |\\n| Errors      | Mede a quantidade de erros que ocorreram ao usar um recurso.                          |\\n| Jitter      | Mede a varia\xe7\xe3o que o pacote na rede \xe9 transmitido e quando ele \xe9 recebido.           |\\n| Capacity    | Mede a quantidade m\xe1xima de trabalho que um sistema pode realizar. Ex: 8GB RAM, 3vCPU |\\n\\n![Metrics](./metrics_resource.png)\\n\\n### 2.2. M\xe9tricas de Servi\xe7o (Four Golden Signals)\\n\\nApresentadas no livro SRE do Google, essas 4 m\xe9tricas s\xe3o destinadas a entender a experi\xeancia de uso do sistema do ponto de vista dos usu\xe1rios - Service-Oriented.\\n\\n| Sinal      | Descri\xe7\xe3o                                                                   |\\n| ---------- | --------------------------------------------------------------------------- |\\n| Latency    | Mede o tempo que o sistema leva para responder a uma solicita\xe7\xe3o.           |\\n| Traffic    | Mede o n\xfamero de requisi\xe7\xf5es que o sistema est\xe1 recebendo.                  |\\n| Errors     | Mede o n\xfamero de erros que o sistema est\xe1 retornando.                       |\\n| Saturation | Mede o grau no qual um recurso est\xe1 perto da sua capacidade m\xe1xima ou al\xe9m. |\\n\\nA m\xe9trica de desempenho mais comum \xe9 a lat\xeancia, que representa o tempo necess\xe1rio para concluir uma unidade de trabalho. **A lat\xeancia pode ser expressa como uma m\xe9dia ou como um percentil, como \\"99% das solicita\xe7\xf5es retornaram em 0,1s\\".**  \\n\\n:::tip\\nA m\xe9dia \xe9 muito usada para entender o desempenho geral de um sistema, por\xe9m a m\xe9dia n\xe3o \xe9 um valor t\xe3o confi\xe1vel, pois pode ser distorcida por valores extremos, j\xe1 os percentis s\xe3o \xfateis para entender o desempenho em diferentes quantis da distribui\xe7\xe3o.\\n:::\\n\\nAbaixo mostro uma dashboard para monitorar o uso total de CPU de um Container. Fiz uma simula\xe7\xe3o de 1000 requests e podemos ver o pico de CPU.\\n\\n![Metrics](./metrics_cpu_user.png)\\n\\n![Metrics](./metrics_memory.png)\\n\\n\\n### 2.2. Algumas Boas Pr\xe1ticas\\n\\n- **F\xe1cil de Entender** Deve ser possivel determinar rapidamente o que cada m\xe9trica ou evento representa.\\n\\n- **Custo** Armazenar m\xe9tricas pode ser caro, ent\xe3o voc\xea deve coletar apenas o que \xe9 realmente necess\xe1rio.\\n\\n- **Granular** Se voc\xea coletar m\xe9tricas muito agregadas, voc\xea pode perder informa\xe7\xf5es importantes. Por exemplo, se voc\xea coletar a m\xe9dia de lat\xeancia de uma solicita\xe7\xe3o, voc\xea pode perder informa\xe7\xf5es sobre picos de lat\xeancia que podem ser importantes para a experi\xeancia do usu\xe1rio. Se voc\xea coletar m\xe9tricas muito granulares, voc\xea pode acabar com muitos dados que s\xe3o dif\xedceis de analisar. Encontre um equil\xedbrio entre a granularidade e a agrega\xe7\xe3o que funcione para voc\xea.\\n\\n- **Etiqueta de Escopo** Cada um dos seus hosts opera simultaneamente em v\xe1rios escopos, e voc\xea pode querer verificar a sa\xfade de qualquer um desses escopos, ou suas combina\xe7\xf5es. Por exemplo: como est\xe1 a m\xe9trica X total? E a m\xe9trica X no Nordeste dos EUA?.\\n\\n- **Vida \xfatil** Mantenha uma pol\xedtica de reten\xe7\xe3o de dados que permita que voc\xea investigue problemas passados e identifique tend\xeancias ao longo do tempo.\\n\\n### 2.3. Arquitetura\\n\\n![Metrics](./metrics.png)\\n\\n### Conclus\xe3o\\n\\nAs m\xe9tricas conseguem informar o estado passado e presente do sistema, e ajudam a prever comportamentos que podem ocorrer no futuro.  \\n\\nRespondem qual parte do software est\xe1 sendo mais acessada, qual parte est\xe1 consumindo mais recursos, qual parte est\xe1 mais lenta...\\n\\nN\xe3o se resumem a apenas m\xe9tricas de recurso, mas tamb\xe9m a m\xe9tricas de neg\xf3cio, como o n\xfamero de vendas, o n\xfamero de usu\xe1rios ativos...  \\n\\nMas lembre-se, m\xe9tricas s\xe3o apenas n\xfameros, e para entender o que esses n\xfameros significam, voc\xea precisa de logs.\\n\\n---\\n\\n## <a name=\\"what-is-tracing\\"></a> 3. \ud83d\udc63 Tracing: Rastreando Segredos\\n\\nO objetivo principal do tracing \xe9 fornecer visibilidade detalhada sobre como o processamento daquela chamada foi feito, e como ela se relaciona com outras chamadas. \\n\\nQuando essa requisi\xe7\xe3o se extende para fora da aplica\xe7\xe3o, o tracing se torna distribu\xeddo, chamamos-o de [Distributed Tracing](#31-distributed-tracing).\\n\\nUma aplica\xe7\xe3o CLI por exemplo, pode ser instrumentada para gerar traces.\\n\\nIsso \xe9 feito registrando cada opera\xe7\xe3o ou evento importante durante o ciclo de vida de uma requisi\xe7\xe3o.\\n\\nUm dos principais componentes do tracing \xe9 o conceito de `span`. \\n\\n```txt\\nTRACE\\n  |-- SPAN\\n  |     |-- LOG\\n  |     |-- LOG\\n  |     |-- LOG\\n  |-- SPAN\\n  |     |-- LOG\\n  |     |-- LOG\\n```\\n\\nNote que um `span` pode conter v\xe1rios `logs`.\\n\\nUm span representa uma unidade de trabalho ou opera\xe7\xe3o e cont\xe9m informa\xe7\xf5es como:\\n\\n- Nome da opera\xe7\xe3o\\n- In\xedcio e fim da opera\xe7\xe3o (timestamps)\\n- Metadados ou atributos adicionais (como IDs de usu\xe1rio, tipos de opera\xe7\xf5es, etc.)\\n- Relacionamento com outros spans (pai-filho)\\n- Logs associados \xe0 opera\xe7\xe3o\\n\\nOs spans podem ser organizados em uma hierarquia que reflete a estrutura da execu\xe7\xe3o da requisi\xe7\xe3o, facilitando a visualiza\xe7\xe3o de como uma requisi\xe7\xe3o \xe9 processada de ponta a ponta dentro de uma aplica\xe7\xe3o.\\n\\n#### Exemplo\\n\\nAbaixo mostro o output de uma classe python que criei que gera logs estruturados. Nela \xe9 poss\xedvel ver dois `spans` que foram gerados para o mesmo `trace_id`.\\n\\nPor\xe9m ela \xe9 b\xe1sica, ou seja, n\xe3o possui o conceito de que um `span` possui `1..N logs`. Vemos que `1 span` possui `1 log`.\\n\\nPerceba que o `trace_id` \xe9 o mesmo para os dois `spans`, isso indica que ambos os `spans` fazem parte da **mesma requisi\xe7\xe3o**.\\n\\nEssa requisi\xe7\xe3o est\xe1 executando 2 m\xe9todos diferentes da aplica\xe7\xe3o, e ambos os m\xe9todos est\xe3o gerando logs.\\n\\n![tracing](./tracing_loggingz.png)\\n\\n### 3.1. Distributed Tracing\\n\\n<img src={require(\\"./tracing_call.png\\").default} alt=\\"Tracing\\" width=\\"400\\"/>\\n\\nO distributed tracing (rastreamento distribu\xeddo) se expande para ambientes onde m\xfaltiplas aplica\xe7\xf5es e servi\xe7os colaboram para processar uma requisi\xe7\xe3o. \\n\\nEm um sistema distribu\xeddo, uma \xfanica requisi\xe7\xe3o pode atravessar v\xe1rias aplica\xe7\xf5es e servi\xe7os, cada um deles contribuindo com uma parte do processamento.\\n\\nO distributed tracing tem como objetivo fornecer visibilidade ponta a ponta de como as requisi\xe7\xf5es fluem atrav\xe9s de um sistema distribu\xeddo, identificando pontos de lat\xeancia, gargalos e falhas.\\n\\n![distributed-tracing](./tracing_oltp.png)\\n\\n### Conclus\xe3o\\n\\nO tracing \xe9 uma ferramenta poderosa para entender como as requisi\xe7\xf5es s\xe3o processadas em uma aplica\xe7\xe3o e como elas se relacionam com outras requisi\xe7\xf5es.\\n\\nO tracing \xe9 especialmente \xfatil em sistemas distribu\xeddos, onde v\xe1rias aplica\xe7\xf5es e servi\xe7os colaboram para processar uma requisi\xe7\xe3o. \\n\\nMas tamb\xe9m \xe9 muito \xfatil em sistemas onde uma requisi\xe7\xe3o pode ser processada por v\xe1rias partes da aplica\xe7\xe3o.\\n\\n---\\n\\n## <a name=\\"what-is-monitoring\\"></a> 4. \ud83d\udea8 Monitoramento: Desvendando Mist\xe9rios em Tempo Real\\n\\nMonitoramento \xe9 o ato de ativamente observar o estado de um sistema para detectar problemas e tomar medidas corretivas.\\n\\nO monitoramento \xe9 uma parte essencial da observabilidade, pois fornece informa\xe7\xf5es em tempo real sobre o estado de um sistema e ajudam a identificar que est\xe1 ocorrendo problemas.\\n\\nUsamos alertas para notificar os operadores do sistema quando alguma politica de alerta \xe9 violada. Esses alertas ajudam a manter os operadores do sistema cientes sobre o que est\xe1 acontecendo.\\n\\nExitem duas abordagens de Monitoramento, chamamos de Ativo e Passivo\\n\\n| Aspecto                   | Monitoramento Ativo                                           | Monitoramento Passivo                                       |\\n| ------------------------- | ------------------------------------------------------------- | ----------------------------------------------------------- |\\n| **M\xe9todo**                | Envia requisi\xe7\xf5es/sondas ao sistema                           | Observa o tr\xe1fego de rede e coleta logs                     |\\n| **Proatividade**          | Proativo                                                      | Reativo                                                     |\\n| **Sobrecarga**            | Pode adicionar carga adicional ao sistema                     | Baixa sobrecarga                                            |\\n| **Detec\xe7\xe3o de Problemas** | Detecta problemas rapidamente atrav\xe9s de sondagens constantes | Pode detectar problemas ap\xf3s eles terem ocorrido            |\\n| **Vantagens**             | Detec\xe7\xe3o r\xe1pida, a\xe7\xe3o preventiva, m\xe9tricas detalhadas         | Baixa sobrecarga, informa\xe7\xf5es detalhadas, an\xe1lise hist\xf3rica |\\n| **Desvantagens**          | Sobrecarga de rede, poss\xedveis falsos positivos                | Reatividade, depend\xeancia de qualidade de logs               |\\n\\nA pr\xe1tica do monitoramento ativo \xe9 comum em sistemas cr\xedticos, onde a detec\xe7\xe3o de problemas e a\xe7\xe3o preventiva s\xe3o essenciais para garantir a disponibilidade e confiabilidade do sistema. \\n\\nPense que voc\xea fica cutucando o sistema para ver se ele est\xe1 responsivo e funcionando como deveria.\\n\\nJ\xe1 a pr\xe1tica do monitoramento passivo \xe9 comum para todos os sistemas.\\n\\n### Conclus\xe3o\\n\\nPara monitorar um sistema de forma eficaz, defina m\xe9tricas e thresholds para que quando um threshold for violado, um alerta seja disparado e o operador do sistema receba notifica\xe7\xe3o.\\n\\nMas tome cuidado com o excesso de alertas, pois isso pode levar a fadiga de alertas e fazer com que os operadores ignorem alertas importantes.\\n\\n---\\n\\n## Refer\xeancias\\n- https://www.oreilly.com/library/view/observability-engineering/9781492076438/\\n- https://www.manning.com/books/software-telemetry\\n- https://sre.google/sre-book/table-of-contents/ (Free to Read Online)"},{"id":"/understand-shell-script","metadata":{"permalink":"/pt-br/blog/understand-shell-script","editUrl":"https://github.com/vinicinbgs/vinicinbgs.github.io/blob/main/blog/understand-shell-script/index.mdx","source":"@site/i18n/pt-br/docusaurus-plugin-content-blog/understand-shell-script/index.mdx","title":"Understand Shell Script","description":"Ill show to you how works a shell script and we go create one example","date":"2022-02-21T00:00:00.000Z","tags":[{"inline":true,"label":"technology","permalink":"/pt-br/blog/tags/technology"},{"inline":true,"label":"shell script","permalink":"/pt-br/blog/tags/shell-script"},{"inline":true,"label":"automation","permalink":"/pt-br/blog/tags/automation"}],"readingTime":6.47,"hasTruncateMarker":false,"authors":[],"frontMatter":{"title":"Understand Shell Script","date":"2022-02-21T00:00:00.000Z","slug":"/understand-shell-script","description":"Ill show to you how works a shell script and we go create one example","tags":["technology","shell script","automation"]},"unlisted":false,"prevItem":{"title":"Desvendando os Segredos do Sistema: A Magia da Observabilidade","permalink":"/pt-br/blog/observability-metrics-and-monitoring"}},"content":"#### Summary:\\n[Repository on GitHub](https://github.com/vinicinbgs/blog-projects/tree/main/shell-script)\\n- 1. [Introduction](#intro)\\n  - 1.1 [Create Example](#create-example)\\n  - 1.2 [Write Example](#write-example)\\n  - 1.3 [Run Example](#run-example)\\n  - 1.4 [Touch Example](#create-new-file-example)\\n- 2. [Loops](#loops)\\n  - 2.1 [For](#loops-for)\\n  - 2.2 [While](#loops-while)\\n- 3. [Comparison](#comparison)\\n  - 3.1 [String Comparison](#string-comparison)\\n  - 3.2 [Numbers Comparison](#numbers-comparison)\\n- 4. [Final Example](#final-example)\\n- 5. [Sources](#sources)\\n\\n---\\n## Goal:\\n---\\nMy intention is to give to you an idea of how you can create your own shell script commands \\nto automate some tasks and show to you some references (https://www.gnu.org/savannah-checkouts/gnu/bash/manual/bash.html) (https://www.shellscript.sh).\\n\\nShell script has Variables, Repetition Structures, Conditional Statements and commands UNIX so you can create\\nscripts to use as entrypoint.sh on docker container or just to automate one boring manual task in your S.O.\\n\\ne.g: This blog is deployed with this [Shell Script](https://github.com/vinicinbgs/vinicinbgs.github.io/blob/main/deploy.sh) that generate a build, commit, push to gh-pages branch in my repo.\\n\\nYou can use CLI commands from others softwares installed in your machine, like GIT, Docker, node, npm...\\n\\nIf you understand the power of shell script your imagination will be the limit.\\n\\nWithout further ado...\\n\\n## <a name=\\"intro\\"></a> 1. Introduction\\n---\\nWhat is Shell Script?\\n\\n- A shell script is a text file that contains a sequence of commands for a UNIX-based \\noperating system. It is called a shell script because it combines a sequence of commands, \\nthat would otherwise have to be typed into the keyboard one at a time, into a single script.\\n\\nA Unix shell is both a command interface and a programming language\\n\\n<p class=\\"hightlight bg-danger\\">\\n  In our case the computer program is <ins>example.sh</ins> file\\n</p>\\n<br />\\n<h4>\\n  <a name=\\"create-example\\"></a>  1.1 Create a file called <ins>example.sh</ins> using terminal, follow:\\n</h4>\\n\\n```bash\\ntouch example.sh\\nchmod +x example.sh\\n```\\n\\n- **touch**: will create the file\\n- **chmod +x**: will give permission to execute file script\\n\\n<p class=\\"hightlight\\">\\n  You can use <strong>touch</strong> and <strong>chmod</strong> commands inside your shell script file too\\n</p>\\n\\n<br />\\n<h4>\\n  <a name=\\"write-example\\"></a> 1.2 Open file <ins>example.sh</ins> in your preferred IDE\\n</h4>\\n\\n```bash\\n#!/bin/sh\\n\\necho \\"Start\\" # this command will output in terminal Start string\\n```\\n\\n- `#!/bin/sh` tells Unix that the file is to be executed by /bin/sh.\\n\\n<br />\\n<h4>\\n  <a name=\\"run-example\\"></a> 1.3 Running file <ins>example.sh</ins> in terminal\\n</h4>\\n\\n```sh\\nsh example.sh\\n```\\n\\n<br />\\n<h4>\\n  <a name=\\"create-new-file-example\\"></a> 1.4 Create a new file using shell script\\n</h4>\\n\\n```bash\\n#!/bin/sh\\necho \\"Start\\"\\ntouch new_file.txt # create new file called new_file.txt\\necho \\"First Line\\">> new_file.txt # append in new_file.txt the text First Line\\n```\\n\\n<br />\\n\\n## <a name=\\"variables\\"></a> 2. Variables\\n---\\nA variable is a character string to which we assign a value. \\nThe value assigned could be a number, text, filename, device, or any other type of data.\\n\\n### 2.1 <a name=\\"variables-declare\\"></a> Declare Variable\\n\\n```bash\\n#!/bin/sh\\n\\nVARIABLE_MY_NAME=\\"Vinicius\\"\\nVARIABLE_TEXT=\\"Hi, my name is \\"\\necho \\"$VARIABLE_TEXT $VARIABLE_MY_NAME\\"\\n```\\n\\nTerminal Output: \\n```sh\\nHi, my name is Vinicius\\n```\\n\\n### 2.2 <a name=\\"variables-user-input\\"></a> Read Input Variable\\n```bash\\n#!/bin/sh\\n\\necho \\"What is your name?\\"\\nread VARIABLE_MY_NAME\\n\\nVARIABLE_TEXT=\\"Hi,\\"\\n\\necho \\"$VARIABLE_TEXT $VARIABLE_MY_NAME\\"\\n```\\n\\nTerminal Output: \\n```sh\\nWhat is your name?\\n> Vinicius\\n\\nHi, Vinicius\\n```\\n\\n<br />\\n\\n## <a name=\\"loops\\"></a> 3. Loops\\n---\\nLoops will enable you to execute one or more commands repeatedly\\n\\n### <a name=\\"loops-for\\"></a> 3.1 For\\n\\n```bash\\n#!/bin/sh\\nfor i in 1 2 3 4 5\\ndo\\n  echo \\"Looping ... number $i\\"\\ndone\\n```\\n\\n### <a name=\\"loops-while\\"></a> 3.2 While\\n\\n```bash\\n#!/bin/sh\\nwhile :\\ndo\\n  echo \\"Please type something in (^C to quit)\\"\\n  read INPUT_STRING\\n  echo \\"You typed: $INPUT_STRING\\"\\ndone\\n```\\n\\n<br />\\n\\n### <a name=\\"comparison\\"></a> 4. Comparison\\n---\\nSometimes you need to check if one variable is equal or not to another or greater/less... <br />\\nIn this section you can check ways to compare numbers and strings variables.\\n#### <a name=\\"numbers-comparison\\"></a> 4.1 Numbers Comparison\\n```bash\\n# is equal to:\\nif [ \\"$a\\" -eq \\"$b\\" ]\\n\\n# is not equal to:\\nif [ \\"$a\\" -ne \\"$b\\" ]\\n\\n# is greater than:\\nif [ \\"$a\\" -gt \\"$b\\" ]\\n\\n# is greater than or equal to:\\nif [ \\"$a\\" -ge \\"$b\\" ]\\n\\n# is less than: -lt\\nif [ \\"$a\\" -lt \\"$b\\" ]\\n\\n# is less than or equal to:\\nif [ \\"$a\\" -le \\"$b\\" ]\\n\\n# is less than (within double parentheses):\\n((\\"$a\\" < \\"$b\\"))\\n\\n# is less than or equal to (within double parentheses):\\n((\\"$a\\" <= \\"$b\\"))\\n\\n# is greater than (within double parentheses):\\n((\\"$a\\" > \\"$b\\"))\\n\\n# is greater than or equal to (within double parentheses):\\n((\\"$a\\" >= \\"$b\\"))\\n```\\n\\n<br />\\n\\n#### <a name=\\"string-comparison\\"></a> 4.2 String Comparison\\n```bash\\n# is equal to: \\nif [ \\"$a\\" = \\"$b\\" ]\\n\\n# is equal to:\\nif [ \\"$a\\" == \\"$b\\" ]\\n\\n# is not equal to:\\nif [ \\"$a\\" != \\"$b\\" ]\\n\\n# is less than, in ASCII alphabetical order:\\nif [[ \\"$a\\" < \\"$b\\" ]]\\n\\n# is greater than, in ASCII alphabetical order:\\nif [[ \\"$a\\" > \\"$b\\" ]]\\n\\n# string is null, that is, has zero length:\\nif [ -z \\"$String\\" ]\\nthen\\n  echo \\"\\\\$String is null.\\"\\nelse\\n  echo \\"\\\\$String is NOT null.\\"\\nfi\\n\\n# string is not null:\\nif [ -n \\"$String\\" ]\\nthen\\n  echo \\"\\\\$String is not null.\\"\\nelse\\n  echo \\"\\\\$String is null.\\"\\nfi\\n```\\n\\n<br />\\n\\n### <a name=\\"final-example\\"></a> 5. Final example.sh\\n---\\nCopy the script below and run it on your machine and after use, edit to your needs\\n\\n[Repository on GitHub](https://github.com/vinicinbgs/article-example-understand-shell-script/blob/main/example.sh)\\n```bash\\n#!bin/sh\\n\\nscript() {\\n    echo \\"Start\\" # Output Start in terminal\\n\\n    # Receive variable by user input\\n    echo \\"Put your name\\"      # Output Put your name in terminal\\n    read name                 # Wait/Receive input variable name by user\\n    echo Your name is ${name} # Output Your name is variable name\\n\\n    # Execute commands of another programs (like docker, git...)\\n    docker -v # docker version\\n    git --version # git version\\n\\n\\n    rm Dockerfile # Remove old Dockerfile\\n    touch Dockerfile # Create Dockerfile\\n    echo \\"FROM alpine:3.14\\" >>Dockerfile # Input echo string inside file\\n    echo \'ENTRYPOINT [\\"echo\\", \\"Container running \ud83d\udc4d ( \u0361\xb0 \u035c\u0296 \u0361\xb0)\\"]\' >>Dockerfile # Input echo string inside file\\n    echo \'CMD [\\"\'${name}\'\\"] && /dev/null\' >>Dockerfile # Input echo string inside file\\n\\n    # Build and Execute Docker Container\\n    imageName=\\"${name}-docker-image\\" # docker image name variable\\n    docker build -t ${imageName} .   # build image\\n    docker images                    # list images\\n\\n    # Generate utils variables\\n    timestamp=$(date +%s)                                 # create variable timestamp to attach in container name\\n    containerName=\\"${name}-docker-container-${timestamp}\\" # variable container name to assign in run command\\n\\n    # Running command and see logs\\n    echo \\"-------\\"\\n    echo \\"Start: \\" && docker run -d --name ${containerName} ${imageName} # running container\\n    echo \\"-------\\"\\n    echo \\"Logs: \\" && docker logs ${containerName} # output logs container\\n    echo \\"-------\\"\\n    # Remove all Containers\\n    containers=$(docker ps -a --format \\"{{.Names}}\\" | grep \\"${name}-docker-container\\") # list all containers created in this script\\n    docker rm -f ${containers}                                                         # remove all containers created in this script\\n    docker ps -a                                                                       # list all containers\\n\\n    # Remove all Images\\n    imgs=$(docker images --format \\"{{.Repository}}\\" | grep \\"${imageName}\\") # imgs created repository\\n    docker rmi -f ${imgs} # Remove images in imgs variable\\n}\\n\\nscript | tee ex.log # fill log file called ex.log\\n```\\n\\nSteps:\\n\\n1. output \\"start\\" in terminal\\n2. output \\"Put your name\\" in terminal\\n3. wait user input variable name\\n4. output \\"Your name is ...\\" in terminal\\n5. check docker version\\n6. check git version\\n7. remove old Dockerfile\\n8. create new Dockerfile empty\\n9. write in file Dockerfile echo string to create a valid docker image\\n10. build image\\n11. run container\\n12. output logs container\\n13. remove all containers created (normally only one)\\n14. remove all images created (normally only one)\\n---\\n<p class=\\"hightlight\\" style={{ backgroundColor: \'yellow\', color: \'black\' }}>\\n  Use SOURCES to study and deepen your knowledge\\n</p>\\n\\n<a name=\\"sources\\"></a> \\n\\nSources: <br />\\n- https://www.gnu.org/software/bash/manual/html_node/index.html (shell)\\n- https://www.shellscript.sh (shell)\\n- https://tldp.org/LDP/abs/html/comparison-ops.html (shell)\\n- https://www.tutorialspoint.com/unix/ (shell)\\n- https://www.oreilly.com/openbook/debian/book/ch13_03.html (shell)\\n- https://en.wikipedia.org/wiki/Tee_(command) (shell)\\n- https://www.techtarget.com/searchdatacenter/definition/shell-script (shell)\\n- https://docs.docker.com/develop/develop-images/dockerfile_best-practices/ (docker)\\n---\\n- https://github.com/vinicinbgs/blog-projects/tree/main/shell-script"}]}}')}}]);